# Dequeue (Alt+Up)

**Status**: todo
**Milestone**: R2
**Category**: Input & Commands

## Description

Pop the last queued message back into the input field. Lets users edit or resubmit accidentally queued messages.

## Architecture

```rust
// Command factory
fn cmd_dequeue(_args: &str) -> Option<Event> {
    Some(Event::Dequeue)
}

// Update handler
fn update_dequeue(state: &mut AppState) {
    if let Some((content, _id)) = state.message_queue.last() {
        state.input_text = content.clone();
        state.input_cursor = state.input_text.len();
        state.message_queue.pop();
    } else {
        state.flash_input_border();
    }
}
```

### Keybinding

```json
{
  "app.message.dequeue": "alt+up"
}
```

## Acceptance Criteria

- [ ] `Alt+Up` pops last queued message into input
- [ ] Message removed from queue (not just copied)
- [ ] Cursor positioned at end
- [ ] Non-empty input is replaced
- [ ] Empty queue flashes input border
- [ ] Works for steering and follow-up queues

## Files

| File | Description |
|------|-------------|
| `crates/runie-core/src/event.rs` | `Dequeue` event |
| `crates/runie-core/src/update/queue.rs` | `update_dequeue()` |
| `crates/runie-term/src/keymap.rs` | Map Alt+Up |

## Tests

### Layer 1 — State/Logic
- [ ] `dequeue_restores_last` — last message → input, removed
- [ ] `dequeue_sets_cursor_end` — cursor at len
- [ ] `dequeue_replaces_input` — old input cleared
- [ ] `dequeue_empty_flashes` — flash when nothing to dequeue
- [ ] `dequeue_lifo` — multiple queued, pops in reverse

### Layer 2 — Event Handling
- [ ] `alt_up_emits_dequeue` — keymap event

//! Command Registry — unified slash commands and command palette

use crate::model::AppState;
use crate::Event;
use std::collections::HashMap;

pub mod handlers;

/// Dialog types that can be opened via commands
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Dialog {
    CommandPalette,
    ModelSelector,
    Settings,
}

/// Result of executing a slash command
#[derive(Debug, Clone, PartialEq)]
pub enum CommandResult {
    Message(String),
    Event(Event),
    OpenDialog(Dialog),
    None,
}

/// Command category for grouping in help and palette
#[derive(Debug, Clone, PartialEq, Eq, Hash, PartialOrd, Ord)]
pub enum CommandCategory {
    Session,
    Model,
    Tool,
    System,
    Help,
}

impl CommandCategory {
    pub fn as_str(&self) -> &'static str {
        match self {
            CommandCategory::Session => "Session",
            CommandCategory::Model => "Model",
            CommandCategory::Tool => "Tool",
            CommandCategory::System => "System",
            CommandCategory::Help => "Help",
        }
    }
}

/// Handler function signature for commands
pub type CommandHandler = fn(&mut AppState, &str) -> CommandResult;

/// Optional completer for command arguments
pub type CommandCompleter = fn(&str) -> Vec<String>;

/// Definition of a single command
#[derive(Clone)]
pub struct CommandDef {
    pub name: String,
    pub description: String,
    pub aliases: Vec<String>,
    pub category: CommandCategory,
    pub handler: CommandHandler,
    pub completer: Option<CommandCompleter>,
}

/// Registry of all available commands
#[derive(Clone)]
pub struct CommandRegistry {
    commands: HashMap<String, CommandDef>,
    aliases: HashMap<String, String>,
}

impl CommandRegistry {
    pub fn new() -> Self {
        let mut registry = Self {
            commands: HashMap::new(),
            aliases: HashMap::new(),
        };
        handlers::register_all(&mut registry);
        registry
    }

    pub fn register(&mut self, def: CommandDef) {
        for alias in &def.aliases {
            self.aliases.insert(alias.clone(), def.name.clone());
        }
        self.commands.insert(def.name.clone(), def);
    }

    pub fn get(&self, name: &str) -> Option<&CommandDef> {
        self.commands
            .get(name)
            .or_else(|| self.aliases.get(name).and_then(|n| self.commands.get(n)))
    }

    pub fn list(&self) -> Vec<&CommandDef> {
        let mut defs: Vec<&CommandDef> = self.commands.values().collect();
        defs.sort_by_key(|d| (&d.category, &d.name));
        defs
    }

    pub fn list_by_category(&self) -> Vec<(CommandCategory, Vec<&CommandDef>)> {
        let defs = self.list();
        let mut result: Vec<(CommandCategory, Vec<&CommandDef>)> = Vec::new();
        for def in defs {
            if let Some(last) = result.last_mut() {
                if last.0 == def.category {
                    last.1.push(def);
                    continue;
                }
            }
            result.push((def.category.clone(), vec![def]));
        }
        result
    }

    pub fn help_text(&self, provider: &str, model: &str) -> String {
        let mut lines = vec!["Commands:".to_string()];
        for (category, defs) in self.list_by_category() {
            lines.push(format!("\n  {}", category.as_str()));
            for def in defs {
                let alias_str = if def.aliases.is_empty() {
                    String::new()
                } else {
                    format!(", {}", def.aliases.join(", "))
                };
                lines.push(format!(
                    "  /{}{} — {}",
                    def.name, alias_str, def.description
                ));
            }
        }
        lines.push(format!(
            "\nCurrent model: {}/{}\nUse Up/Down to navigate history.\nEnter — send | Alt+Enter — follow-up | Esc — abort | Ctrl+S — steer",
            provider, model
        ));
        lines.join("\n")
    }
}

impl Default for CommandRegistry {
    fn default() -> Self {
        Self::new()
    }
}

impl AppState {
    /// Dispatch a slash command through the registry.
    /// Returns `None` for non-slash input so caller can treat it as a user message.
    pub(crate) fn handle_slash(&mut self, content: &str) -> Option<CommandResult> {
        if !content.starts_with('/') {
            return None;
        }
        let input = content.trim_start_matches('/');
        let (name, args) = input.split_once(' ').unwrap_or((input, ""));
        match self.registry.get(name) {
            Some(cmd) => Some((cmd.handler)(self, args)),
            None => Some(CommandResult::Message(format!(
                "Unknown command: /{name}. Try /help."
            ))),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn registry_get_by_name() {
        let state = AppState::default();
        let cmd = state.registry.get("model");
        assert!(cmd.is_some());
        assert_eq!(cmd.unwrap().name, "model");
    }

    #[test]
    fn registry_get_by_alias() {
        let state = AppState::default();
        let cmd = state.registry.get("m");
        assert!(cmd.is_some());
        assert_eq!(cmd.unwrap().name, "model");
    }

    #[test]
    fn registry_list_returns_all() {
        let state = AppState::default();
        let defs = state.registry.list();
        assert!(
            defs.len() >= 22,
            "registry should have 22+ commands, got {}",
            defs.len()
        );
    }

    #[test]
    fn registry_list_groups_by_category() {
        let state = AppState::default();
        let groups = state.registry.list_by_category();
        assert!(!groups.is_empty());
        let total: usize = groups.iter().map(|g| g.1.len()).sum();
        assert!(total >= 22);
    }

    #[test]
    fn handler_model_switches() {
        let mut state = AppState::default();
        let cmd = state.registry.get("model").unwrap();
        let result = (cmd.handler)(&mut state, "gpt-4o");
        assert_eq!(state.current_model, "gpt-4o");
        assert!(matches!(result, CommandResult::Message(_)));
    }

    #[test]
    fn handler_help_generates_list() {
        let mut state = AppState::default();
        let cmd = state.registry.get("help").unwrap();
        let result = (cmd.handler)(&mut state, "");
        if let CommandResult::Message(msg) = result {
            assert!(msg.contains("Commands:"));
            assert!(msg.contains("/model"));
            assert!(msg.contains("/save"));
        } else {
            panic!("help should return Message, got {:?}", result);
        }
    }

    #[test]
    fn handler_quit_sets_flag() {
        let mut state = AppState::default();
        let cmd = state.registry.get("quit").unwrap();
        let result = (cmd.handler)(&mut state, "");
        assert!(matches!(result, CommandResult::Event(Event::Quit)));
        state.update(Event::Quit);
        assert!(state.should_quit);
    }

    #[test]
    fn unknown_command_returns_error() {
        let mut state = AppState::default();
        let result = state.handle_slash("/foo");
        assert!(matches!(result, Some(CommandResult::Message(msg)) if msg.contains("Unknown command")));
    }

    #[test]
    fn slash_event_dispatches_to_registry() {
        let mut state = AppState::default();
        type_str(&mut state, "/model gpt-4o");
        state.update(Event::Submit);
        assert_eq!(state.current_model, "gpt-4o");
    }

    #[test]
    fn alias_event_dispatches_correctly() {
        let mut state = AppState::default();
        type_str(&mut state, "/m gpt-4o");
        state.update(Event::Submit);
        assert_eq!(state.current_model, "gpt-4o");
    }

    fn type_str(state: &mut AppState, text: &str) {
        for c in text.chars() {
            state.update(Event::Input(c));
        }
    }
}

//! Model — Application State (mutable borrow, no cloning per event)
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;


const SPINNER_CHARS: &[char] = &['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠹', '⠸', '⠴', '⠼'];
const SPINNER_FRAMES: u32 = 12;

/// A viewport into the element cache — elements plus how many
/// lines to skip from the top of the first element.
#[derive(Clone, Copy)]
pub struct VisibleRegion<'a> {
    pub elements: &'a [Element],
    pub skip_lines: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum QueuedMessageKind {
    Steering,
    FollowUp,
}

#[derive(Clone, Debug, PartialEq, Eq)]
#[derive(Default)]
pub enum DeliveryMode {
    /// Each message triggers a separate LLM call
    #[default]
    OneAtATime,
    /// All queued messages delivered together in one LLM call
    All,
}


#[derive(Clone, Debug)]
pub struct QueuedMessage {
    pub content: String,
    pub kind: QueuedMessageKind,
}

#[derive(Clone)]
pub struct AppState {
    pub messages: Vec<ChatMessage>,
    pub input: String,
    /// Cursor position in input (0 = before first char)
    pub cursor_pos: usize,
    pub streaming: bool,
    pub scroll: usize,
    pub thinking_started_at: Option<std::time::Instant>,
    pub request_queue: std::collections::VecDeque<(String, String)>,
    pub message_queue: Vec<QueuedMessage>,
    /// How steering messages are delivered to the LLM
    pub steering_mode: DeliveryMode,
    /// How follow-up messages are delivered to the LLM
    pub follow_up_mode: DeliveryMode,
    pub next_id: u64,
    pub current_request_id: Option<String>,
    pub turn_started_at: Option<std::time::Instant>,
    pub current_tool_name: Option<String>,
    pub tool_started_at: Option<std::time::Instant>,
    pub intermediate_step_count: usize,
    pub animation_frame: u32,
    pub turn_active: bool,
    pub current_action: Option<String>,
    pub current_provider: String,
    pub current_model: String,
    /// Active theme name (resolved by runie-tui)
    pub theme_name: String,
    /// Command registry for slash command dispatch
    pub registry: crate::commands::CommandRegistry,
    /// Set to true when the user requests quit
    pub should_quit: bool,
    /// Currently open dialog (if any)
    pub open_dialog: Option<crate::commands::Dialog>,
    /// Default provider from config (for /new reset)
    pub config_provider: String,
    /// Default model from config (for /new reset)
    pub config_model: String,

    /// Number of commands sent to agent but not yet completed
    pub inflight: usize,
    /// @-ref file lookup suggestions
    pub at_suggestions: Option<Vec<String>>,
    /// Selected index in @-ref suggestions
    pub at_selected: Option<usize>,
    /// Last @-ref query to avoid redundant filesystem calls
    pub last_at_query: Option<String>,
    /// Global collapse flag — when true, ALL thoughts/tools render collapsed.
    /// New elements automatically respect this setting.
    pub all_collapsed: bool,
    /// Cached index of last assistant message — O(1) lookup for append_response
    pub(crate) last_assistant_index: Option<usize>,
    pub(crate) thought_seq: u64,
    pub(crate) input_history: Vec<String>,
    pub(crate) history_pos: Option<usize>,
    pub(crate) undo_stack: Vec<(String, usize)>,
    pub(crate) redo_stack: Vec<(String, usize)>,
    pub input_flash: u8,
    pub placeholder: String,
    element_count: usize,
    elements_cache: Vec<Element>,
    line_counts: Vec<usize>,
    total_lines: usize,
    dirty: bool,
    message_gen: u64,
    cached_gen: u64,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            messages: Vec::new(), input: String::new(), cursor_pos: 0,
            streaming: false, scroll: 0, thinking_started_at: None,
            request_queue: std::collections::VecDeque::new(),
            message_queue: Vec::new(),
            steering_mode: DeliveryMode::OneAtATime,
            follow_up_mode: DeliveryMode::OneAtATime,
            next_id: 0,
            current_request_id: None, turn_started_at: None,
            current_tool_name: None, tool_started_at: None,
            intermediate_step_count: 0, animation_frame: 0,
            turn_active: false, current_action: None,
            current_provider: "mock".into(), current_model: "echo".into(),
            theme_name: "silkcircuit-neon".into(),
            registry: crate::commands::CommandRegistry::new(),
            should_quit: false,
            open_dialog: None,
            config_provider: "mock".into(),
            config_model: "echo".into(),
            inflight: 0,
            at_suggestions: None, at_selected: None, last_at_query: None,
            all_collapsed: false, last_assistant_index: None, thought_seq: 0,
            input_history: Vec::new(), history_pos: None,
            undo_stack: Vec::new(), redo_stack: Vec::new(),
            input_flash: 0, placeholder: "Type a message to start...".into(),
            element_count: 0, elements_cache: Vec::new(),
            line_counts: Vec::new(), total_lines: 0,
            dirty: true, message_gen: 1, cached_gen: 0,
        }
    }
}

impl AppState {
    pub fn thinking_elapsed_secs(&self) -> Option<f64> {
        self.thinking_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn turn_elapsed_secs(&self) -> Option<f64> {
        self.turn_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn tool_elapsed_secs(&self) -> Option<f64> {
        self.tool_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    /// Braille spinner frame (12-frame cycle)
    pub fn spinner_frame(&self) -> char {
        SPINNER_CHARS[(self.animation_frame % SPINNER_FRAMES) as usize]
    }

    pub fn next_id(&mut self) -> String {
        let id = format!("req.{}", self.next_id);
        self.next_id += 1;
        id
    }

    pub(crate) fn mark_dirty(&mut self) {
        self.dirty = true;
    }

    pub(crate) fn messages_changed(&mut self) {
        self.message_gen = self.message_gen.wrapping_add(1);
        self.dirty = true;
    }

    pub fn cache_generation(&self) -> u64 {
        self.message_gen
    }

    /// Rebuild cache only when messages changed — O(n) but gated
    pub fn ensure_fresh(&mut self) {
        if self.dirty && self.message_gen != self.cached_gen {
            self.elements_cache = crate::ui::LazyCache::rebuild(self);
            self.element_count = self.elements_cache.len();
            self.line_counts = self.elements_cache.iter().map(|e| e.line_count()).collect();
            self.total_lines = self.line_counts.iter().sum();
            self.cached_gen = self.message_gen;
        }
        self.dirty = false;
    }

    /// Visible elements slice — O(1), zero allocation
    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        if self.elements_cache.is_empty() {
            return &[];
        }
        let start = skip.min(self.element_count).min(self.elements_cache.len());
        let end = (start + take).min(self.element_count).min(self.elements_cache.len());
        &self.elements_cache[start..end]
    }

    pub fn count(&self) -> usize {
        self.element_count.max(self.elements_cache.len())
    }

    pub fn element_count(&self) -> usize {
        self.element_count
    }

    pub fn total_lines(&self) -> usize {
        self.total_lines
    }

    pub fn elements_cache(&self) -> &[Element] {
        &self.elements_cache
    }

    pub fn tick_animation(&mut self) {
        let mut changed = false;
        if self.turn_active {
            self.animation_frame = self.animation_frame.wrapping_add(1);
            changed = true;
        }
        if self.input_flash > 0 {
            self.input_flash -= 1;
            changed = true;
        }
        if changed {
            self.dirty = true;
        }
    }

    /// Build an immutable Snapshot for the render actor.
    /// The event loop calls this after ensure_fresh(); the render
    /// actor receives it via channel and draws without touching state.
    pub fn snapshot(&self) -> Snapshot {
        Snapshot {
            elements: self.elements_cache.clone(),
            line_counts: self.line_counts.clone(),
            total_lines: self.total_lines,
            input: self.input.clone(),
            cursor_pos: self.cursor_pos,
            hint_text: self.hint_text(),
            at_suggestions: self.at_suggestions.clone(),
            at_selected: self.at_selected,
            turn_active: self.turn_active,
            input_flash: self.input_flash,
            placeholder: self.placeholder.clone(),
            spinner_frame: self.spinner_frame(),
            scroll: self.scroll,
            turn_elapsed_secs: self.turn_elapsed_secs(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
            theme_name: self.theme_name.clone(),
            queue_count: self.message_queue.len() + self.request_queue.len(),
        }
    }

    pub fn is_dirty(&self) -> bool {
        self.dirty
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        #[allow(clippy::manual_checked_ops)]
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements_cache.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements_cache.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements_cache[start_idx..end_idx.min(self.elements_cache.len())],
            skip_lines,
        }
    }

    pub fn total_tokens(&self) -> usize {
        self.messages.iter().map(|m| crate::tokens::estimate_tokens(&m.content)).sum()
    }

    pub fn compact(&mut self, keep_recent_tokens: usize) -> String {
        let total = self.total_tokens();
        if total <= keep_recent_tokens {
            return format!("Session has {} tokens, no compaction needed", total);
        }
        let mut accumulated = 0usize;
        let mut cut_idx = 0usize;
        for (i, msg) in self.messages.iter().enumerate().rev() {
            accumulated += crate::tokens::estimate_tokens(&msg.content);
            if accumulated >= keep_recent_tokens {
                cut_idx = i;
                break;
            }
        }
        while cut_idx < self.messages.len() {
            match self.messages[cut_idx].role {
                Role::User | Role::Assistant => break,
                _ => cut_idx += 1,
            }
        }
        if cut_idx == 0 {
            return "Cannot compact: all messages are recent".to_string();
        }
        let removed_count = cut_idx;
        self.messages.drain(..cut_idx);
        let summary = format!("[Compacted: {} earlier messages removed, keeping ~{} tokens]", removed_count, keep_recent_tokens);
        self.messages.insert(0, ChatMessage {
            role: Role::System,
            content: summary.clone(),
            timestamp: now(),
            id: "compaction".to_string(),
        });
        self.messages_changed();
        summary
    }
}

pub fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

#[derive(Clone, Debug, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub enum Role {
    User,
    Thought,
    Assistant,
    Tool,
    TurnComplete,
    System,
}

impl Role {
    pub fn as_str(&self) -> &'static str {
        match self {
            Role::User => "user",
            Role::Thought => "thought",
            Role::Assistant => "assistant",
            Role::Tool => "tool",
            Role::TurnComplete => "turn_complete",
            Role::System => "system",
        }
    }
}

#[derive(Clone, Debug, serde::Serialize, serde::Deserialize)]
pub struct ChatMessage {
    pub role: Role,
    pub content: String,
    pub timestamp: f64,
    pub id: String,
}

//! Crossterm key event → CoreEvent conversion with configurable keybindings.

use crossterm::event::{Event, KeyCode, KeyEvent, KeyEventKind, KeyModifiers};
use runie_core::{Event as CoreEvent, keybindings};
use std::collections::HashMap;

pub fn convert_event(event: &Event, bindings: &HashMap<String, String>) -> Option<CoreEvent> {
    log_key_event(event);
    match event {
        Event::Paste(data) => Some(CoreEvent::Paste(data.clone())),
        Event::Key(key) if key.kind == KeyEventKind::Press || key.kind == KeyEventKind::Repeat => {
            map_key_event(key, bindings)
        }
        _ => None,
    }
}

fn log_key_event(event: &Event) {
    if let Event::Key(key) = event {
        if std::env::var("RUNIE_DEBUG").is_ok() {
            use std::io::Write;
            let _ = std::fs::OpenOptions::new()
                .create(true)
                .append(true)
                .open("/tmp/runie_keys.log")
                .and_then(|mut f| writeln!(f, "{:?}", key));
        }
    }
}

pub fn key_event_to_combo(key: &KeyEvent) -> String {
    let mut parts = Vec::new();
    if key.modifiers.contains(KeyModifiers::CONTROL) {
        parts.push("ctrl");
    }
    if key.modifiers.contains(KeyModifiers::ALT) {
        parts.push("alt");
    }
    if key.modifiers.contains(KeyModifiers::SHIFT) {
        parts.push("shift");
    }
    let key_name = match key.code {
        KeyCode::Char('\t') => "tab".to_string(),
        KeyCode::Char(c) => c.to_lowercase().to_string(),
        KeyCode::Enter => "enter".to_string(),
        KeyCode::Esc => "escape".to_string(),
        KeyCode::Backspace => "backspace".to_string(),
        KeyCode::Tab | KeyCode::BackTab => "tab".to_string(),
        KeyCode::Delete => "delete".to_string(),
        KeyCode::Up => "up".to_string(),
        KeyCode::Down => "down".to_string(),
        KeyCode::Left => "left".to_string(),
        KeyCode::Right => "right".to_string(),
        KeyCode::Home => "home".to_string(),
        KeyCode::End => "end".to_string(),
        KeyCode::Insert => "insert".to_string(),
        KeyCode::PageUp => "pageup".to_string(),
        KeyCode::PageDown => "pagedown".to_string(),
        KeyCode::F(n) => format!("f{}", n),
        _ => return String::new(),
    };
    parts.push(&key_name);
    parts.join("+")
}

fn map_key_event(key: &KeyEvent, bindings: &HashMap<String, String>) -> Option<CoreEvent> {
    let combo = key_event_to_combo(key);
    if !combo.is_empty() {
        if let Some(event_name) = bindings.get(&combo) {
            if let Some(evt) = keybindings::event_from_name(event_name) {
                return Some(evt);
            }
        }
    }
    if key.modifiers.contains(KeyModifiers::CONTROL) {
        map_ctrl_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::ALT) {
        map_alt_key(key.code)
    } else if key.modifiers.contains(KeyModifiers::SHIFT) {
        map_shift_key(key.code)
    } else {
        map_plain_key(key.code)
    }
}

fn map_ctrl_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Char('e') | KeyCode::Char('E') => Some(CoreEvent::ToggleExpand),
        KeyCode::Char('j') | KeyCode::Char('J') => Some(CoreEvent::Newline),
        KeyCode::Char('a') | KeyCode::Char('A') => Some(CoreEvent::CursorStart),
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorLeft),
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorRight),
        KeyCode::Char('w') | KeyCode::Char('W') => Some(CoreEvent::DeleteWord),
        KeyCode::Char('k') | KeyCode::Char('K') => Some(CoreEvent::DeleteToEnd),
        KeyCode::Char('u') | KeyCode::Char('U') => Some(CoreEvent::DeleteToStart),
        KeyCode::Char('d') | KeyCode::Char('D') => Some(CoreEvent::KillChar),
        KeyCode::Char('z') | KeyCode::Char('Z') => Some(CoreEvent::Undo),
        KeyCode::Char('y') | KeyCode::Char('Y') => Some(CoreEvent::Redo),
        KeyCode::Char('c') | KeyCode::Char('C') => Some(CoreEvent::Quit),
        KeyCode::Char('s') | KeyCode::Char('S') => Some(CoreEvent::Abort),
        _ => None,
    }
}

fn map_alt_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Enter => Some(CoreEvent::FollowUp),
        KeyCode::Char('b') | KeyCode::Char('B') => Some(CoreEvent::CursorWordLeft),
        KeyCode::Char('f') | KeyCode::Char('F') => Some(CoreEvent::CursorWordRight),
        _ => None,
    }
}

fn map_shift_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Enter => Some(CoreEvent::Newline),
        _ => None,
    }
}

fn map_plain_key(code: KeyCode) -> Option<CoreEvent> {
    match code {
        KeyCode::Esc => Some(CoreEvent::Abort),
        KeyCode::Char('\t') | KeyCode::Tab | KeyCode::BackTab => Some(CoreEvent::Input('\t')),
        KeyCode::Char(c) => Some(CoreEvent::Input(c)),
        KeyCode::Backspace => Some(CoreEvent::Backspace),
        KeyCode::Enter => Some(CoreEvent::Submit),
        KeyCode::Up => Some(CoreEvent::HistoryPrev),
        KeyCode::Down => Some(CoreEvent::HistoryNext),
        KeyCode::Left => Some(CoreEvent::CursorLeft),
        KeyCode::Right => Some(CoreEvent::CursorRight),
        KeyCode::Home => Some(CoreEvent::CursorStart),
        KeyCode::End => Some(CoreEvent::CursorEnd),
        KeyCode::Delete => Some(CoreEvent::KillChar),
        _ => None,
    }
}

